import asyncMap from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/async-map.js";

describe("asyncMap abort behavior", () => {
  it("should immediately invoke cb with abort error when aborted flag is already set", (done) => {
    let pendingSourceCb: ((end: any, data?: any) => void) | null = null;
    let pendingMapCb: ((err: any, data?: any) => void) | null = null;

    const source = (abort: any, cb: (end: any, data?: any) => void) => {
      if (abort) { cb(abort); return; }
      pendingSourceCb = cb;
    };

    const slowMap = (data: any, cb: (err: any, data?: any) => void) => {
      pendingMapCb = cb;
    };

    const through = asyncMap(slowMap);
    const stream = through(source);

    // Trigger first read - source hangs
    stream(null, () => {});
    // Resolve source with data - now map is busy
    pendingSourceCb!(null, 42);

    // Now busy=true, abort the stream to set aborted
    const abortError = new Error("abort");
    stream(abortError, () => {
      // abort acknowledged
    });

    // aborted is now set. Complete the map to clear busy and trigger abortCb
    pendingMapCb!(null, 99);

    // Now aborted=true, busy=false. A new read should immediately return aborted.
    let cbCalledSynchronously = false;
    stream(null, (end: any) => {
      cbCalledSynchronously = true;
      expect(end).toBe(abortError);
      done();
    });

    // Check synchronous behavior
    if (!cbCalledSynchronously) {
      done(new Error("cb was not called synchronously - mutation detected"));
    }
  });
});
