import asyncMap from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/async-map.js";

describe("asyncMap abort behavior", () => {
  it("should immediately call cb with abort error on reads after stream has been aborted", (done) => {
    let pendingSourceCb: ((end: any, data?: any) => void) | null = null;
    let pendingMapCb: ((err: any, data?: any) => void) | null = null;
    let abortSourceCb: ((end: any, data?: any) => void) | null = null;

    const source = (abort: any, cb: (end: any, data?: any) => void) => {
      if (abort) {
        abortSourceCb = cb;
        return;
      }
      pendingSourceCb = cb;
    };

    const slowMap = (data: any, cb: (err: any, data?: any) => void) => {
      pendingMapCb = cb;
    };

    const through = asyncMap(slowMap);
    const stream = through(source);

    // Step 1: Start a read - source hangs
    stream(null, () => {});
    expect(pendingSourceCb).not.toBeNull();

    // Step 2: Resolve source with data - map becomes busy
    pendingSourceCb!(null, 42);
    expect(pendingMapCb).not.toBeNull();

    // Step 3: Abort while busy - sets aborted, reads from source with abort
    const abortError = new Error("abort");
    let abortCbCalled = false;
    stream(abortError, () => {
      abortCbCalled = true;
    });

    // aborted is set, busy is true, so abortCb is stored
    // Step 4: Complete the map - busy becomes false, abortCb gets called
    pendingMapCb!(null, 99);
    // Now aborted is set, busy is false

    // Step 5: Make another read - in original, if(aborted) return cb(aborted) fires immediately
    let immediatelyCalled = false;
    let receivedError: any = null;
    stream(null, (end: any, data?: any) => {
      immediatelyCalled = true;
      receivedError = end;
    });

    // In original code: cb is called synchronously with abortError
    // In mutated code: the if(false) check is skipped, so it tries to read from source
    if (immediatelyCalled) {
      expect(receivedError).toBe(abortError);
      done();
    } else {
      done(new Error("Expected cb to be called immediately with abort error (mutation detected: if(aborted) was changed to if(false))"));
    }
  });
});
